    override fun method1() {
        println("Functional Method 1")
    }

    override fun method2() {
        println("Functional Method 2")
    }
}

fun main() {
    val instanceB = ClassB()
    instanceB.normalMethod()
    instanceB.method1()
    instanceB.method2()
